window.BACTERIAL_QUESTIONS=window.BACTERIAL_QUESTIONS.concat([{"id":"Q101","topic":"carbuncle","topicEn":"Carbuncle","topicAr":"الجَمْرَة","type":"MCQ","difficulty":"Easy","source":"PDF p. 24","question":{"en":"What distinguishes a carbuncle anatomically?","ar":"ما الذي يميز الجمرة تشريحيًا؟"},"options":[{"letter":"A","en":"Interconnected infection of multiple adjacent follicles","ar":"عدوى مترابطة لعدة جريبات متجاورة"},{"letter":"B","en":"A single superficial epidermal erosion","ar":"تآكل بشروي سطحي منفرد"},{"letter":"C","en":"Only lymphatic inflammation","ar":"التهاب لمفي فقط"},{"letter":"D","en":"A noninfectious pigment disorder","ar":"اضطراب صبغي غير معدٍ"}],"correct":"A","explanation":{"en":"A carbuncle is a deep connected infection involving a cluster of adjacent follicles and subcutaneous tissue.","ar":"الجمرة عدوى عميقة مترابطة تشمل مجموعة من الجريبات المتجاورة والأنسجة تحت الجلد."},"reasoning":{"en":"Focus on multiple follicles form one larger inflammatory mass. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تكوّن عدة جريبات كتلة التهابية أكبر واحدة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q102","topic":"carbuncle","topicEn":"Carbuncle","topicAr":"الجَمْرَة","type":"MCQ","difficulty":"Medium","source":"PDF pp. 24-25","question":{"en":"Which physical finding is most characteristic of a carbuncle?","ar":"أي علامة بالفحص هي الأكثر تميزًا للجمرة؟"},"options":[{"letter":"A","en":"Multiple draining sinuses","ar":"جيوب متعددة مفرغة للقيح"},{"letter":"B","en":"Coral-red fluorescence","ar":"تألق أحمر مرجاني"},{"letter":"C","en":"Honey-colored superficial crust only","ar":"قشرة عسلية سطحية فقط"},{"letter":"D","en":"A solitary tiny follicular pustule","ar":"بثرة جريبية صغيرة منفردة"}],"correct":"A","explanation":{"en":"Carbuncles form a painful firm mass with multiple pustules or draining sinus openings.","ar":"تكوّن الجمرة كتلة صلبة مؤلمة ذات بثور متعددة أو فتحات جيوب مفرغة."},"reasoning":{"en":"Focus on multiple drainage points reflect interconnected follicles. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تعكس نقاط التصريف المتعددة ترابط الجريبات المصابة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q103","topic":"carbuncle","topicEn":"Carbuncle","topicAr":"الجَمْرَة","type":"MCQ","difficulty":"Easy","source":"PDF pp. 24-25","question":{"en":"Where do carbuncles commonly occur?","ar":"أين تظهر الجمرات شائعًا؟"},"options":[{"letter":"A","en":"Nape of neck, shoulders, back, hips, and thighs","ar":"مؤخرة الرقبة والكتفان والظهر والوركان والفخذان"},{"letter":"B","en":"Only the lips","ar":"الشفتان فقط"},{"letter":"C","en":"Only toe webs","ar":"بين أصابع القدم فقط"},{"letter":"D","en":"Only eyelids","ar":"الجفون فقط"}],"correct":"A","explanation":{"en":"Carbuncles commonly arise on thick, friction-prone skin such as the nape, back, shoulders, hips, and thighs.","ar":"تظهر الجمرات غالبًا في الجلد السميك المعرض للاحتكاك مثل مؤخرة الرقبة والظهر والكتفين والوركين والفخذين."},"reasoning":{"en":"Focus on thick skin and friction favor deep interconnected infection. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يساعد الجلد السميك والاحتكاك على العدوى العميقة المترابطة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q104","topic":"carbuncle","topicEn":"Carbuncle","topicAr":"الجَمْرَة","type":"Case","difficulty":"Medium","source":"PDF pp. 24-25","question":{"en":"A middle-aged man with diabetes has a large painful neck mass with several draining openings and fever. What is the diagnosis?","ar":"رجل متوسط العمر مصاب بالسكري لديه كتلة كبيرة مؤلمة بالرقبة مع عدة فتحات مفرغة وحمى. ما التشخيص؟"},"options":[{"letter":"A","en":"Carbuncle","ar":"جمرة"},{"letter":"B","en":"Furuncle","ar":"دمل"},{"letter":"C","en":"Erythrasma","ar":"إريثرازما"},{"letter":"D","en":"Non-bullous impetigo","ar":"قوباء غير فقاعية"}],"correct":"A","explanation":{"en":"A large deep mass with multiple sinuses, systemic symptoms, and diabetes is classic for a carbuncle.","ar":"الكتلة العميقة الكبيرة ذات الجيوب المتعددة والأعراض الجهازية مع السكري نموذجية للجمرة."},"reasoning":{"en":"Focus on multiple connected drainage points separate it from a single boil. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تميز نقاط التصريف المتعددة المتصلة الجمرة عن الدمل المنفرد. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q105","topic":"carbuncle","topicEn":"Carbuncle","topicAr":"الجَمْرَة","type":"MCQ","difficulty":"Medium","source":"PDF pp. 24-25","question":{"en":"Which systemic manifestations may accompany a carbuncle?","ar":"ما الأعراض الجهازية التي قد تصاحب الجمرة؟"},"options":[{"letter":"A","en":"High fever, malaise, and marked fatigue","ar":"حمى شديدة وإعياء وتعب واضح"},{"letter":"B","en":"No systemic symptoms by definition","ar":"غياب الأعراض الجهازية بحكم التعريف"},{"letter":"C","en":"Isolated visual loss only","ar":"فقد بصر منفرد فقط"},{"letter":"D","en":"Chronic painless jaundice","ar":"يرقان مزمن غير مؤلم"}],"correct":"A","explanation":{"en":"Carbuncles are deeper and larger than furuncles and may cause fever, malaise, leukocytosis, and prostration.","ar":"الجمرات أعمق وأكبر من الدمامل وقد تسبب الحمى والإعياء وكثرة الكريات البيضاء والوهن."},"reasoning":{"en":"Focus on systemic illness reflects the larger bacterial and inflammatory burden. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يعكس المرض الجهازي العبء البكتيري والالتهابي الأكبر. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q106","topic":"carbuncle","topicEn":"Carbuncle","topicAr":"الجَمْرَة","type":"Treatment","difficulty":"Medium","source":"PDF p. 24","question":{"en":"What is the usual treatment for a carbuncle?","ar":"ما العلاج المعتاد للجمرة؟"},"options":[{"letter":"A","en":"Incision and drainage plus systemic antibiotics","ar":"الشق والتصريف مع مضادات حيوية جهازية"},{"letter":"B","en":"Topical moisturizer only","ar":"مرطب موضعي فقط"},{"letter":"C","en":"Observation without source control","ar":"المراقبة دون السيطرة على المصدر"},{"letter":"D","en":"Antiviral therapy","ar":"علاج مضاد للفيروسات"}],"correct":"A","explanation":{"en":"Carbuncles require source control and systemic therapy because they are deep, interconnected, and often associated with systemic illness.","ar":"تحتاج الجمرات إلى السيطرة على المصدر وعلاج جهازي لأنها عميقة ومترابطة وغالبًا ترتبط بمرض جهازي."},"reasoning":{"en":"Focus on drainage alone may not address surrounding and systemic infection. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على قد لا يعالج التصريف وحده العدوى المحيطة والجهازية. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q107","topic":"carbuncle","topicEn":"Carbuncle","topicAr":"الجَمْرَة","type":"Case","difficulty":"Hard","source":"PDF pp. 23-25","question":{"en":"Which feature most strongly distinguishes a carbuncle from a furuncle?","ar":"أي علامة تميز الجمرة بقوة أكبر عن الدمل؟"},"options":[{"letter":"A","en":"A cluster of interconnected follicles with multiple sinuses","ar":"مجموعة جريبات مترابطة مع جيوب متعددة"},{"letter":"B","en":"Staphylococcus aureus as the pathogen","ar":"المكورات العنقودية الذهبية كممرض"},{"letter":"C","en":"Pain and erythema","ar":"الألم والاحمرار"},{"letter":"D","en":"Occurrence in a friction area","ar":"الحدوث في منطقة احتكاك"}],"correct":"A","explanation":{"en":"Both may be painful staphylococcal infections in friction areas, but only a carbuncle characteristically connects multiple follicles and drains through several openings.","ar":"قد يكون كلاهما عدوى عنقودية مؤلمة في مناطق الاحتكاك، لكن الجمرة تتميز بترابط جريبات متعددة وتصريفها عبر فتحات عدة."},"reasoning":{"en":"Focus on the number and interconnection of involved follicles is the defining distinction. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على عدد الجريبات المصابة وترابطها هو الفارق المحدد. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q108","topic":"carbuncle","topicEn":"Carbuncle","topicAr":"الجَمْرَة","type":"Image","difficulty":"Medium","source":"PDF p. 24","question":{"en":"The image shows a large inflamed mass with several pustular and draining points. What is the diagnosis?","ar":"تُظهر الصورة كتلة التهابية كبيرة ذات عدة نقاط بثرية ومفرغة. ما التشخيص؟"},"options":[{"letter":"A","en":"Carbuncle","ar":"جمرة"},{"letter":"B","en":"Single furuncle","ar":"دمل منفرد"},{"letter":"C","en":"Erythrasma","ar":"إريثرازما"},{"letter":"D","en":"Impetigo","ar":"قوباء"}],"correct":"A","explanation":{"en":"Multiple drainage points in a single large deep mass are typical of a carbuncle.","ar":"تُعد نقاط التصريف المتعددة داخل كتلة عميقة كبيرة واحدة نموذجية للجمرة."},"reasoning":{"en":"Focus on the image demonstrates connected follicular abscesses rather than one isolated boil. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على توضح الصورة خراجات جريبية متصلة بدل دمل منفرد. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":"data:image/webp;base64,"},{"id":"Q109","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"MCQ","difficulty":"Easy","source":"PDF pp. 27-28","question":{"en":"Which organism is the main cause of cat scratch disease?","ar":"ما الكائن المسبب الرئيسي لمرض خدش القطة؟"},"options":[{"letter":"A","en":"Bartonella henselae","ar":"بارتونيلا هينسيلا"},{"letter":"B","en":"Staphylococcus aureus","ar":"المكورات العنقودية الذهبية"},{"letter":"C","en":"Bacillus anthracis","ar":"العصوية الجمرية"},{"letter":"D","en":"Corynebacterium minutissimum","ar":"الوتدية الدقيقة"}],"correct":"A","explanation":{"en":"Cat scratch disease is caused mainly by Bartonella henselae.","ar":"ينتج مرض خدش القطة أساسًا عن بارتونيلا هينسيلا."},"reasoning":{"en":"Focus on the organism is linked to cats as a natural reservoir. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يرتبط الميكروب بالقطط كمستودع طبيعي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q110","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"MCQ","difficulty":"Easy","source":"PDF pp. 27-28","question":{"en":"How is cat scratch disease most commonly transmitted to humans?","ar":"كيف ينتقل مرض خدش القطة إلى الإنسان غالبًا؟"},"options":[{"letter":"A","en":"A scratch, bite, or lick from an infected cat, especially a kitten","ar":"خدش أو عضة أو لعق من قطة مصابة، خصوصًا الصغيرة"},{"letter":"B","en":"Long-distance airborne spread","ar":"انتقال هوائي لمسافات طويلة"},{"letter":"C","en":"Contaminated drinking water only","ar":"مياه شرب ملوثة فقط"},{"letter":"D","en":"Tick bite exclusively","ar":"لدغة قراد حصريًا"}],"correct":"A","explanation":{"en":"B. henselae is inoculated through scratches, bites, or saliva contacting broken skin; kittens and flea exposure are common clues.","ar":"تدخل بارتونيلا عبر الخدوش أو العضات أو اللعاب الملامس لجلد متشقق، وتعد القطط الصغيرة والبراغيث دلائل شائعة."},"reasoning":{"en":"Focus on the exposure history directs attention to the inoculation site and draining nodes. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يوجه تاريخ التعرض الانتباه لموضع التلقيح والعقد المصرفة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q111","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"Case","difficulty":"Medium","source":"PDF p. 29","question":{"en":"A papule appears on a child’s hand one week after a kitten scratch. When did this lesion most likely develop relative to exposure?","ar":"ظهرت حطاطة على يد طفل بعد خدش قطة صغيرة بأسبوع. متى تظهر آفة التلقيح عادةً بالنسبة للتعرض؟"},"options":[{"letter":"A","en":"About 3-10 days later","ar":"بعد نحو 3-10 أيام"},{"letter":"B","en":"Immediately within seconds only","ar":"فورًا خلال ثوان فقط"},{"letter":"C","en":"After 5-10 years","ar":"بعد 5-10 سنوات"},{"letter":"D","en":"Only after lymph nodes resolve","ar":"فقط بعد زوال العقد اللمفية"}],"correct":"A","explanation":{"en":"The primary inoculation lesion typically appears 3-10 days after the scratch or bite.","ar":"تظهر آفة التلقيح الأولية عادةً بعد 3-10 أيام من الخدش أو العضة."},"reasoning":{"en":"Focus on the one-week interval is typical for the local lesion. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على الفاصل الزمني لأسبوع نموذجي للآفة الموضعية. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q112","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"MCQ","difficulty":"Medium","source":"PDF p. 29","question":{"en":"Which lymph-node groups are commonly involved in cat scratch disease?","ar":"ما مجموعات العقد اللمفية التي تُصاب شائعًا في مرض خدش القطة؟"},"options":[{"letter":"A","en":"Axillary, epitrochlear, cervical, or submandibular nodes","ar":"العقد الإبطية أو فوق اللقيمة أو العنقية أو تحت الفك"},{"letter":"B","en":"Only inguinal nodes in every case","ar":"العقد الأربية فقط في كل الحالات"},{"letter":"C","en":"Only mediastinal nodes","ar":"العقد المنصفية فقط"},{"letter":"D","en":"No lymph nodes are involved","ar":"لا تُصاب أي عقد لمفية"}],"correct":"A","explanation":{"en":"Nodes draining the inoculation site are involved, commonly axillary, epitrochlear, cervical, supraclavicular, or submandibular.","ar":"تُصاب العقد المصرفة لموضع التلقيح، وأكثرها الإبطية وفوق اللقيمة والعنقية وفوق الترقوة وتحت الفك."},"reasoning":{"en":"Focus on nodal location should anatomically match the site of inoculation. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على ينبغي أن يتوافق موضع العقد تشريحيًا مع موضع التلقيح. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q113","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"Case","difficulty":"Medium","source":"PDF pp. 27, 29","question":{"en":"A healthy child has a healed scratch and one tender axillary node but is otherwise well. What is the expected natural history?","ar":"طفل سليم لديه خدش ملتئم وعقدة إبطية مؤلمة واحدة لكنه بخير عمومًا. ما المسار الطبيعي المتوقع؟"},"options":[{"letter":"A","en":"Usually self-limited over weeks to months","ar":"غالبًا محدود ذاتيًا خلال أسابيع إلى أشهر"},{"letter":"B","en":"Uniform progression to septic shock","ar":"تطور دائم إلى صدمة إنتانية"},{"letter":"C","en":"Permanent generalized lymphadenopathy in all cases","ar":"تضخم عقدي عام دائم في كل الحالات"},{"letter":"D","en":"Immediate skin necrosis","ar":"نخر جلدي فوري"}],"correct":"A","explanation":{"en":"Typical localized CSD is usually benign and resolves spontaneously, although nodes may persist for months.","ar":"غالبًا يكون مرض خدش القطة الموضعي حميدًا ويزول تلقائيًا، رغم أن العقد قد تستمر أشهرًا."},"reasoning":{"en":"Focus on localized disease in an immunocompetent child differs from disseminated disease. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يختلف المرض الموضعي في طفل سليم المناعة عن المرض المنتشر. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q114","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"Case","difficulty":"Hard","source":"PDF p. 29","question":{"en":"A child with recent cat exposure has prolonged fever, abdominal pain, weight loss, and multiple hypodense liver and spleen lesions. What complication is most likely?","ar":"طفل تعرض حديثًا لقطة لديه حمى مطولة وألم بطني ونقص وزن وآفات متعددة منخفضة الكثافة بالكبد والطحال. ما المضاعفة الأرجح؟"},"options":[{"letter":"A","en":"Hepatosplenic cat scratch disease","ar":"مرض خدش القطة الكبدي الطحالي"},{"letter":"B","en":"Simple localized impetigo","ar":"قوباء موضعية بسيطة"},{"letter":"C","en":"Erythrasma","ar":"إريثرازما"},{"letter":"D","en":"Uncomplicated folliculitis","ar":"التهاب جريبات بسيط"}],"correct":"A","explanation":{"en":"Disseminated CSD may cause hepatic and splenic granulomatous lesions with persistent fever and abdominal symptoms.","ar":"قد يسبب مرض خدش القطة المنتشر آفات حبيبومية بالكبد والطحال مع حمى مستمرة وأعراض بطنية."},"reasoning":{"en":"Focus on systemic symptoms plus characteristic visceral imaging indicate dissemination. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تشير الأعراض الجهازية مع تصوير الأحشاء المميز إلى الانتشار. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q115","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"Case","difficulty":"Hard","source":"PDF p. 30","question":{"en":"A patient has unilateral conjunctivitis with tender preauricular lymphadenopathy after a cat licked near the eye. What syndrome is most likely?","ar":"مريض لديه التهاب ملتحمة أحادي مع عقدة أمام الأذن مؤلمة بعد لعق قطة قرب العين. ما المتلازمة الأرجح؟"},"options":[{"letter":"A","en":"Parinaud oculoglandular syndrome","ar":"متلازمة بارينو العينية الغدية"},{"letter":"B","en":"Staphylococcal scalded skin syndrome","ar":"متلازمة الجلد المسموط العنقودية"},{"letter":"C","en":"Gas gangrene","ar":"الغرغرينا الغازية"},{"letter":"D","en":"Sycosis barbae","ar":"التهاب جريبات اللحية العميق"}],"correct":"A","explanation":{"en":"Parinaud oculoglandular syndrome combines unilateral ocular infection with regional preauricular, submandibular, or cervical lymphadenopathy.","ar":"تجمع متلازمة بارينو العينية الغدية بين عدوى عينية أحادية وتضخم عقدي موضعي أمام الأذن أو تحت الفك أو بالرقبة."},"reasoning":{"en":"Focus on ocular inoculation plus draining-node enlargement defines the syndrome. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يحدد التلقيح العيني مع تضخم العقد المصرفة المتلازمة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q116","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"MCQ","difficulty":"Hard","source":"PDF p. 30","question":{"en":"Which ocular finding is characteristic of CSD neuroretinitis?","ar":"أي علامة عينية تميز التهاب الشبكية والعصب البصري في مرض خدش القطة؟"},"options":[{"letter":"A","en":"Optic-disc edema with a macular star","ar":"وذمة قرص العصب البصري مع نجمة بقعية"},{"letter":"B","en":"Coral-red fluorescence of the cornea","ar":"تألق أحمر مرجاني للقرنية"},{"letter":"C","en":"A black eyelid eschar in every case","ar":"قشرة سوداء بالجفن في كل الحالات"},{"letter":"D","en":"Bilateral cataracts","ar":"ساد ثنائي"}],"correct":"A","explanation":{"en":"CSD neuroretinitis can produce optic nerve edema, retinal hemorrhages, cotton-wool spots, and a macular star.","ar":"قد يسبب التهاب الشبكية والعصب البصري في مرض خدش القطة وذمة العصب ونزوفًا شبكية وبقعًا قطنية ونجمة بقعية."},"reasoning":{"en":"Focus on the macular star is a classic ophthalmic clue in the correct exposure context. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على النجمة البقعية دليل عيني كلاسيكي مع سياق التعرض المناسب. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q117","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"Case","difficulty":"Hard","source":"PDF p. 30","question":{"en":"Several weeks after cat-associated lymphadenopathy, a patient develops abrupt confusion and may progress to coma. Which manifestation should be suspected?","ar":"بعد عدة أسابيع من تضخم عقدي مرتبط بقطة، أصيب مريض بارتباك مفاجئ وقد يتطور إلى غيبوبة. ما المظهر الذي يُشتبه فيه؟"},"options":[{"letter":"A","en":"CSD encephalopathy","ar":"اعتلال دماغي بسبب مرض خدش القطة"},{"letter":"B","en":"Localized erythrasma","ar":"إريثرازما موضعية"},{"letter":"C","en":"Simple bullous impetigo","ar":"قوباء فقاعية بسيطة"},{"letter":"D","en":"Furuncle","ar":"دمل"}],"correct":"A","explanation":{"en":"Encephalopathy is the most common neurologic CSD manifestation and can begin abruptly 1-6 weeks after adenopathy.","ar":"الاعتلال الدماغي هو أكثر المظاهر العصبية شيوعًا وقد يبدأ فجأة بعد 1-6 أسابيع من التضخم العقدي."},"reasoning":{"en":"Focus on the timing after lymphadenopathy and acute mental-status change point to neurologic dissemination. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يشير التوقيت بعد التضخم العقدي وتغير الوعي الحاد إلى انتشار عصبي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q118","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"MCQ","difficulty":"Hard","source":"PDF p. 31","question":{"en":"Which statement about Bartonella serology is correct?","ar":"أي عبارة عن الفحوص المصلية لبارتونيلا صحيحة؟"},"options":[{"letter":"A","en":"A negative result does not completely exclude CSD","ar":"النتيجة السلبية لا تستبعد مرض خدش القطة تمامًا"},{"letter":"B","en":"A positive result always proves active acute infection","ar":"النتيجة الإيجابية تثبت دائمًا عدوى حادة نشطة"},{"letter":"C","en":"Serology is never useful in atypical disease","ar":"الفحص المصلي غير مفيد أبدًا في المرض غير النمطي"},{"letter":"D","en":"One negative test permanently rules out disease","ar":"اختبار سلبي واحد يستبعد المرض نهائيًا"}],"correct":"A","explanation":{"en":"Serology can support diagnosis, but negative tests do not rule it out and positive tests may reflect past infection or cross-reactivity.","ar":"قد يدعم الفحص المصلي التشخيص، لكن السلبية لا تستبعده والإيجابية قد تعكس عدوى سابقة أو تفاعلًا متصالبًا."},"reasoning":{"en":"Focus on test limitations require interpretation with exposure and clinical findings. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تتطلب حدود الاختبار تفسيره مع التعرض والنتائج السريرية. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q119","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"Treatment","difficulty":"Hard","source":"PDF p. 31","question":{"en":"When is tissue sampling most appropriate in suspected CSD?","ar":"متى يكون أخذ عينة نسيجية مناسبًا أكثر في الاشتباه بمرض خدش القطة؟"},"options":[{"letter":"A","en":"Prolonged systemic symptoms or concern for malignancy, TB, or another diagnosis","ar":"أعراض جهازية مطولة أو الاشتباه في ورم أو سل أو تشخيص بديل"},{"letter":"B","en":"Every typical mild case immediately","ar":"كل حالة نموذجية خفيفة فورًا"},{"letter":"C","en":"Only after complete resolution","ar":"فقط بعد الزوال الكامل"},{"letter":"D","en":"Never under any circumstance","ar":"لا يُجرى مطلقًا"}],"correct":"A","explanation":{"en":"Biopsy is not routine in classic disease but is useful when symptoms persist or alternative diagnoses need exclusion; PCR or histopathology may support CSD.","ar":"الخزعة ليست روتينية في المرض الكلاسيكي لكنها مفيدة عند استمرار الأعراض أو الحاجة لاستبعاد تشخيصات بديلة، وقد يدعم PCR أو الفحص النسيجي المرض."},"reasoning":{"en":"Focus on diagnostic uncertainty and prolonged illness justify invasive confirmation. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يبرر عدم اليقين التشخيصي وطول المرض التأكيد التدخلي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q120","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"Treatment","difficulty":"Medium","source":"PDF p. 32","question":{"en":"Which regimen is first-line in the chapter for uncomplicated CSD lymphadenitis?","ar":"ما النظام الأول المذكور في الفصل لالتهاب العقد اللمفية غير المعقد بمرض خدش القطة؟"},"options":[{"letter":"A","en":"A 5-day course of azithromycin","ar":"أزيثروميسين لمدة 5 أيام"},{"letter":"B","en":"IV meropenem for 60 days","ar":"ميروبينيم وريدي لمدة 60 يومًا"},{"letter":"C","en":"Topical mupirocin only","ar":"ميوبيروسين موضعي فقط"},{"letter":"D","en":"No follow-up because nodes never suppurate","ar":"لا متابعة لأن العقد لا تتقيح"}],"correct":"A","explanation":{"en":"The chapter recommends a 5-day azithromycin course to shorten lymph-node symptoms, while acknowledging that some experts observe uncomplicated cases.","ar":"يوصي الفصل بأزيثروميسين لمدة 5 أيام لتقصير أعراض العقد، مع الإشارة إلى أن بعض الخبراء يراقبون الحالات غير المعقدة."},"reasoning":{"en":"Focus on the treatment aims to reduce duration rather than drain a non-suppurative node. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يهدف العلاج لتقليل المدة وليس لتصريف عقدة غير متقيحة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q121","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"Treatment","difficulty":"Medium","source":"PDF p. 32","question":{"en":"A painful CSD lymph node becomes fluctuant and suppurative. What adjunctive procedure may relieve symptoms?","ar":"أصبحت عقدة مؤلمة في مرض خدش القطة متموجة ومتقيحة. ما الإجراء المساعد الذي قد يخفف الأعراض؟"},"options":[{"letter":"A","en":"Needle aspiration","ar":"الشفط بالإبرة"},{"letter":"B","en":"Routine complete surgical excision first","ar":"الاستئصال الجراحي الكامل روتينيًا أولًا"},{"letter":"C","en":"Debridement of normal skin","ar":"تنضير الجلد الطبيعي"},{"letter":"D","en":"No intervention even if very painful","ar":"عدم التدخل حتى مع الألم الشديد"}],"correct":"A","explanation":{"en":"Needle aspiration may relieve painful suppurative nodes; surgical excision is rarely needed and reserved for uncertainty or refractory disease.","ar":"قد يخفف الشفط بالإبرة ألم العقد المتقيحة، بينما نادرًا ما يلزم الاستئصال الجراحي ويُحجز لعدم اليقين أو المرض المقاوم."},"reasoning":{"en":"Focus on aspiration provides symptom relief while avoiding unnecessary excision. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يوفر الشفط تخفيفًا للأعراض مع تجنب الاستئصال غير الضروري. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q122","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"Image","difficulty":"Medium","source":"PDF pp. 27, 29","question":{"en":"The image shows a small inoculation papule on the hand after a kitten scratch. What later finding is most expected?","ar":"تُظهر الصورة حطاطة تلقيح صغيرة باليد بعد خدش قطة صغيرة. ما العلامة اللاحقة الأكثر توقعًا؟"},"options":[{"letter":"A","en":"Tender regional lymphadenopathy proximal to the lesion","ar":"تضخم عقدي موضعي مؤلم قريب من الآفة"},{"letter":"B","en":"Immediate generalized desquamation","ar":"تقشر جلدي عام فوري"},{"letter":"C","en":"Coral-red flexural fluorescence","ar":"تألق أحمر مرجاني بالثنيات"},{"letter":"D","en":"Multiple draining neck sinuses from a carbuncle","ar":"جيوب رقبة متعددة مفرغة بسبب جمرة"}],"correct":"A","explanation":{"en":"The primary lesion is followed by enlargement of the draining lymph nodes, often about two weeks after exposure.","ar":"تتبع الآفة الأولية زيادة حجم العقد اللمفية المصرفة، وغالبًا بعد نحو أسبوعين من التعرض."},"reasoning":{"en":"Focus on the local inoculation site predicts the anatomical nodal basin. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يتنبأ موضع التلقيح بالحوض العقدي التشريحي المصاب. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":"data:image/webp;base64,"},{"id":"Q123","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"Image","difficulty":"Hard","source":"PDF p. 29","question":{"en":"The image shows regional lymph-node swelling in a patient with cat exposure and prolonged fever. Which additional evaluation is most important if abdominal pain is present?","ar":"تُظهر الصورة تضخمًا عقديًا موضعيًا لدى مريض تعرض لقطة ولديه حمى مطولة. ما التقييم الإضافي الأهم إذا وُجد ألم بطني؟"},"options":[{"letter":"A","en":"Ultrasound or CT of the liver and spleen","ar":"موجات فوق صوتية أو أشعة مقطعية للكبد والطحال"},{"letter":"B","en":"Wood lamp examination of the groin only","ar":"فحص الأربية بمصباح وود فقط"},{"letter":"C","en":"No investigation because dissemination cannot occur","ar":"لا فحوص لأن الانتشار غير ممكن"},{"letter":"D","en":"Immediate skin debridement","ar":"تنضير جلدي فوري"}],"correct":"A","explanation":{"en":"Persistent fever and abdominal pain raise concern for hepatosplenic CSD, which may show multiple liver or spleen lesions on imaging.","ar":"تثير الحمى المستمرة والألم البطني القلق من مرض خدش القطة الكبدي الطحالي الذي قد يظهر آفات متعددة بالتصوير."},"reasoning":{"en":"Focus on systemic symptoms beyond regional nodes should trigger evaluation for dissemination. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يجب أن تدفع الأعراض الجهازية التي تتجاوز العقد الموضعية إلى تقييم الانتشار. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":"data:image/webp;base64,"},{"id":"Q124","topic":"cat-scratch","topicEn":"Cat Scratch Disease","topicAr":"مرض خدش القطة","type":"Case","difficulty":"Hard","source":"PDF p. 33","question":{"en":"An adult has CSD neuroretinitis with acute visual loss. Which regimen best matches the chapter?","ar":"بالغ لديه التهاب شبكية وعصب بصري بسبب مرض خدش القطة مع فقد بصر حاد. أي نظام يتوافق مع الفصل؟"},"options":[{"letter":"A","en":"Doxycycline plus rifampin for 4-6 weeks, with ophthalmology follow-up and adjunctive corticosteroids","ar":"دوكسيسيكلين مع ريفامبين لمدة 4-6 أسابيع مع متابعة عيون وكورتيكوستيرويد مساعد"},{"letter":"B","en":"Topical erythromycin for two days only","ar":"إريثرومايسين موضعي ليومين فقط"},{"letter":"C","en":"Cephalexin alone for three days","ar":"سيفاليكسين وحده لثلاثة أيام"},{"letter":"D","en":"No therapy because visual disease is always harmless","ar":"لا علاج لأن المرض البصري غير خطير دائمًا"}],"correct":"A","explanation":{"en":"Neuroretinitis is treated with doxycycline plus rifampin for 4-6 weeks; adjunctive corticosteroids and close ophthalmologic monitoring are suggested.","ar":"يُعالج التهاب الشبكية والعصب البصري بالدوكسيسيكلين مع الريفامبين لمدة 4-6 أسابيع، مع اقتراح كورتيكوستيرويد مساعد ومتابعة عيون دقيقة."},"reasoning":{"en":"Focus on sight-threatening dissemination requires prolonged combination therapy rather than the short lymphadenitis regimen. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يتطلب الانتشار المهدد للبصر علاجًا مركبًا مطولًا بدل نظام التهاب العقد القصير. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q125","topic":"anthrax","topicEn":"Cutaneous Anthrax","topicAr":"الجمرة الخبيثة الجلدية","type":"MCQ","difficulty":"Easy","source":"PDF p. 34","question":{"en":"Which organism causes cutaneous anthrax?","ar":"ما الكائن المسبب للجمرة الخبيثة الجلدية؟"},"options":[{"letter":"A","en":"Bacillus anthracis","ar":"العصوية الجمرية"},{"letter":"B","en":"Bartonella henselae","ar":"بارتونيلا هينسيلا"},{"letter":"C","en":"Corynebacterium minutissimum","ar":"الوتدية الدقيقة"},{"letter":"D","en":"Streptococcus pyogenes","ar":"العقدية المقيحة"}],"correct":"A","explanation":{"en":"Cutaneous anthrax is a zoonotic infection caused by the spore-forming, toxin-producing Bacillus anthracis.","ar":"الجمرة الخبيثة الجلدية عدوى حيوانية المنشأ تسببها العصوية الجمرية المكوّنة للأبواغ والمنتجة للسموم."},"reasoning":{"en":"Focus on the spore-forming zoonotic organism explains the exposure pattern and prolonged prophylaxis after aerosol exposure. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يفسر الميكروب الحيواني المكوّن للأبواغ نمط التعرض وطول الوقاية بعد التعرض الهوائي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q126","topic":"anthrax","topicEn":"Cutaneous Anthrax","topicAr":"الجمرة الخبيثة الجلدية","type":"MCQ","difficulty":"Easy","source":"PDF p. 34","question":{"en":"Which exposure most strongly suggests cutaneous anthrax?","ar":"أي تعرض يرجح الجمرة الخبيثة الجلدية أكثر؟"},"options":[{"letter":"A","en":"Handling infected animal hides or wool through broken skin","ar":"التعامل مع جلود أو صوف حيوانات مصابة عبر جلد متشقق"},{"letter":"B","en":"Sharing a towel with a child with impetigo","ar":"مشاركة منشفة مع طفل لديه قوباء"},{"letter":"C","en":"Using a hot tub","ar":"استخدام حوض ساخن"},{"letter":"D","en":"Close shaving of the beard","ar":"حلاقة اللحية عن قرب"}],"correct":"A","explanation":{"en":"Spores enter through cuts or abrasions after contact with infected animals, hides, wool, meat, or contaminated material.","ar":"تدخل الأبواغ عبر الجروح أو السحجات بعد ملامسة حيوانات مصابة أو الجلود أو الصوف أو اللحوم أو مواد ملوثة."},"reasoning":{"en":"Focus on occupational or animal-product exposure is the key epidemiologic clue. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على التعرض المهني أو لمنتجات الحيوانات هو الدليل الوبائي الأساسي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q127","topic":"anthrax","topicEn":"Cutaneous Anthrax","topicAr":"الجمرة الخبيثة الجلدية","type":"MCQ","difficulty":"Medium","source":"PDF pp. 34-35","question":{"en":"What is the characteristic lesion progression in cutaneous anthrax?","ar":"ما التسلسل المميز لآفة الجمرة الخبيثة الجلدية؟"},"options":[{"letter":"A","en":"Pruritic papule → vesicle or bulla → painless black eschar","ar":"حطاطة حاكة ← حويصلة أو فقاعة ← قشرة سوداء غير مؤلمة"},{"letter":"B","en":"Honey crust → follicular pustules → coral fluorescence","ar":"قشرة عسلية ← بثور جريبية ← تألق مرجاني"},{"letter":"C","en":"Diffuse erythema → raised sharp plaque → lymphatic streak","ar":"احمرار منتشر ← لويحة مرتفعة حادة ← خط لمفي"},{"letter":"D","en":"Tender nodule → several connected sinuses","ar":"عقدة مؤلمة ← جيوب متعددة متصلة"}],"correct":"A","explanation":{"en":"The lesion evolves from an itchy papule to a fluid-filled lesion and then a necrotic ulcer with a black eschar.","ar":"تتطور الآفة من حطاطة حاكة إلى آفة مملوءة بالسائل ثم قرحة نخرية ذات قشرة سوداء."},"reasoning":{"en":"Focus on the orderly evolution and painless necrotic center are highly characteristic. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على التطور المتسلسل والمركز النخري غير المؤلم علامتان شديدتا التميز. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q128","topic":"anthrax","topicEn":"Cutaneous Anthrax","topicAr":"الجمرة الخبيثة الجلدية","type":"Case","difficulty":"Hard","source":"PDF pp. 34-35","question":{"en":"A severe-looking black eschar is surrounded by marked non-pitting edema, but the lesion is painless. What is the most likely diagnosis?","ar":"قشرة سوداء تبدو شديدة محاطة بوذمة واضحة غير انطباعية لكن الآفة غير مؤلمة. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Cutaneous anthrax","ar":"الجمرة الخبيثة الجلدية"},{"letter":"B","en":"Furuncle","ar":"دمل"},{"letter":"C","en":"Ecthyma","ar":"إكثيما"},{"letter":"D","en":"Cellulitis alone","ar":"التهاب نسيج خلوي فقط"}],"correct":"A","explanation":{"en":"A painless black eschar with edema much larger than the lesion is a classic diagnostic combination for cutaneous anthrax.","ar":"القشرة السوداء غير المؤلمة مع وذمة أكبر بكثير من الآفة مزيج تشخيصي كلاسيكي للجمرة الخبيثة الجلدية."},"reasoning":{"en":"Focus on the mismatch between dramatic appearance and minimal pain separates anthrax from many pyogenic lesions. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يفرق عدم التناسب بين المظهر الشديد وقلة الألم الجمرة الخبيثة عن كثير من الآفات القيحية. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q129","topic":"anthrax","topicEn":"Cutaneous Anthrax","topicAr":"الجمرة الخبيثة الجلدية","type":"MCQ","difficulty":"Hard","source":"PDF p. 35","question":{"en":"Which anthrax toxin component is mainly responsible for marked local edema?","ar":"أي مكوّن من سموم الجمرة الخبيثة مسؤول أساسًا عن الوذمة الموضعية الشديدة؟"},"options":[{"letter":"A","en":"Edema factor","ar":"عامل الوذمة"},{"letter":"B","en":"Lethal factor only","ar":"العامل القاتل فقط"},{"letter":"C","en":"Protective antigen alone as the edema-producing enzyme","ar":"المستضد الواقي وحده كإنزيم مولد للوذمة"},{"letter":"D","en":"Exfoliative toxin B","ar":"السم التقشري B"}],"correct":"A","explanation":{"en":"Edema factor drives massive edema, while lethal factor contributes to tissue necrosis and protective antigen permits toxin entry into cells.","ar":"يسبب عامل الوذمة التورم الشديد، بينما يساهم العامل القاتل في نخر الأنسجة ويسمح المستضد الواقي بدخول السموم إلى الخلايا."},"reasoning":{"en":"Focus on matching each toxin component to its function prevents confusion between swelling and necrosis mechanisms. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تمنع مطابقة كل مكوّن بوظيفته الخلط بين آليات التورم والنخر. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q130","topic":"anthrax","topicEn":"Cutaneous Anthrax","topicAr":"الجمرة الخبيثة الجلدية","type":"Image","difficulty":"Medium","source":"PDF p. 35","question":{"en":"The image shows a painless black eschar with surrounding edema. What is the most likely diagnosis?","ar":"تُظهر الصورة قشرة سوداء غير مؤلمة مع وذمة محيطة. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Cutaneous anthrax","ar":"الجمرة الخبيثة الجلدية"},{"letter":"B","en":"Non-bullous impetigo","ar":"القوباء غير الفقاعية"},{"letter":"C","en":"Erythrasma","ar":"الإريثرازما"},{"letter":"D","en":"Simple folliculitis","ar":"التهاب جريبات بسيط"}],"correct":"A","explanation":{"en":"The black eschar and disproportionate edema are classic for cutaneous anthrax.","ar":"تُعد القشرة السوداء والوذمة غير المتناسبة علامتين كلاسيكيتين للجمرة الخبيثة الجلدية."},"reasoning":{"en":"Focus on the visual combination is more specific than either finding alone. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على المزيج البصري أكثر نوعية من كل علامة منفردة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":"data:image/webp;base64,"},{"id":"Q131","topic":"anthrax","topicEn":"Cutaneous Anthrax","topicAr":"الجمرة الخبيثة الجلدية","type":"Treatment","difficulty":"Medium","source":"PDF pp. 34-36","question":{"en":"What is a first-line treatment for uncomplicated naturally acquired cutaneous anthrax without systemic signs?","ar":"ما علاج الخط الأول للجمرة الخبيثة الجلدية الطبيعية غير المعقدة دون علامات جهازية؟"},"options":[{"letter":"A","en":"Doxycycline or ciprofloxacin for about 7-10 days","ar":"دوكسيسيكلين أو سيبروفلوكساسين لنحو 7-10 أيام"},{"letter":"B","en":"Topical clindamycin only","ar":"كليندامايسين موضعي فقط"},{"letter":"C","en":"Incision and drainage of the eschar","ar":"شق وتصريف القشرة"},{"letter":"D","en":"Oral fluconazole","ar":"فلوكونازول فموي"}],"correct":"A","explanation":{"en":"Doxycycline or ciprofloxacin is used for uncomplicated cutaneous disease, typically for 7-10 days after natural exposure.","ar":"يُستخدم الدوكسيسيكلين أو السيبروفلوكساسين للمرض الجلدي غير المعقد عادةً لمدة 7-10 أيام بعد التعرض الطبيعي."},"reasoning":{"en":"Focus on systemic active therapy is required even though the lesion is localized. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يلزم علاج جهازي فعال رغم موضعية الآفة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q132","topic":"anthrax","topicEn":"Cutaneous Anthrax","topicAr":"الجمرة الخبيثة الجلدية","type":"Treatment","difficulty":"Hard","source":"PDF pp. 35, 42-44","question":{"en":"Why is treatment extended to about 60 days after suspected aerosol exposure?","ar":"لماذا يُمدد العلاج إلى نحو 60 يومًا بعد الاشتباه في التعرض بالهباء؟"},"options":[{"letter":"A","en":"Dormant spores may germinate late","ar":"قد تنبت الأبواغ الكامنة متأخرًا"},{"letter":"B","en":"The skin cannot absorb any antibiotic for two months","ar":"لا يمتص الجلد أي مضاد لمدة شهرين"},{"letter":"C","en":"All antibiotics work only after day 59","ar":"لا تعمل المضادات إلا بعد اليوم 59"},{"letter":"D","en":"The black eschar must remain for exactly 60 days","ar":"يجب أن تبقى القشرة السوداء 60 يومًا بالضبط"}],"correct":"A","explanation":{"en":"Aerosol exposure can leave dormant spores that germinate over time, requiring prolonged treatment or post-exposure prophylaxis.","ar":"قد يترك التعرض الهوائي أبواغًا كامنة تنبت بمرور الوقت، مما يستلزم علاجًا أو وقاية مطولة بعد التعرض."},"reasoning":{"en":"Focus on duration is driven by spore biology rather than the visible skin lesion alone. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تحدد بيولوجيا الأبواغ المدة وليس مظهر الآفة الجلدية وحده. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q133","topic":"anthrax","topicEn":"Cutaneous Anthrax","topicAr":"الجمرة الخبيثة الجلدية","type":"Treatment","difficulty":"Hard","source":"PDF p. 36","question":{"en":"What is the correct surgical approach to an uncomplicated anthrax eschar?","ar":"ما النهج الجراحي الصحيح لقشرة الجمرة الخبيثة غير المعقدة؟"},"options":[{"letter":"A","en":"Avoid routine excision or debridement","ar":"تجنب الاستئصال أو التنضير الروتيني"},{"letter":"B","en":"Excise it immediately in every case","ar":"استئصالها فورًا في كل حالة"},{"letter":"C","en":"Repeatedly puncture the eschar","ar":"ثقب القشرة بصورة متكررة"},{"letter":"D","en":"Perform cosmetic curettage before antibiotics","ar":"كحت تجميلي قبل المضادات"}],"correct":"A","explanation":{"en":"Routine manipulation may spread infection and is avoided; surgery is reserved for compartment syndrome, circulatory compromise, or airway threat.","ar":"قد ينشر التلاعب الروتيني العدوى ولذلك يُتجنب، وتُحجز الجراحة لمتلازمة الحيز أو تهديد الدورة الدموية أو مجرى الهواء."},"reasoning":{"en":"Focus on the eschar is not a routine abscess requiring source-control incision. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على القشرة ليست خراجًا روتينيًا يحتاج شقًا للسيطرة على المصدر. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q134","topic":"anthrax","topicEn":"Cutaneous Anthrax","topicAr":"الجمرة الخبيثة الجلدية","type":"Case","difficulty":"Hard","source":"PDF pp. 36-38","question":{"en":"A patient with cutaneous anthrax develops shock and signs of systemic spread. Which management principle is correct?","ar":"مريض بالجمرة الخبيثة الجلدية تطورت لديه صدمة وعلامات انتشار جهازي. أي مبدأ علاجي صحيح؟"},"options":[{"letter":"A","en":"Use combination IV antibiotics plus antitoxin and ICU support","ar":"استخدام مضادات وريدية مركبة مع مضاد سموم ودعم بالعناية المركزة"},{"letter":"B","en":"Continue topical therapy alone","ar":"استمرار العلاج الموضعي وحده"},{"letter":"C","en":"Wait for definitive culture before treatment","ar":"انتظار المزرعة النهائية قبل العلاج"},{"letter":"D","en":"Use antitoxin without antibiotics","ar":"استخدام مضاد السموم دون مضادات"}],"correct":"A","explanation":{"en":"Systemic anthrax requires immediate multidrug IV therapy, toxin-neutralizing therapy, and aggressive supportive care.","ar":"تحتاج الجمرة الخبيثة الجهازية إلى علاج وريدي متعدد فوري وعلاج معادل للسموم ودعم مكثف."},"reasoning":{"en":"Focus on both bacterial replication and circulating toxin must be addressed. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يجب معالجة تكاثر البكتيريا والسموم الدائرة معًا. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q135","topic":"anthrax","topicEn":"Cutaneous Anthrax","topicAr":"الجمرة الخبيثة الجلدية","type":"Treatment","difficulty":"Hard","source":"PDF p. 37","question":{"en":"Which regimen illustrates the chapter approach to systemic anthrax with suspected meningitis?","ar":"أي نظام يوضح نهج الفصل للجمرة الخبيثة الجهازية مع الاشتباه في التهاب السحايا؟"},"options":[{"letter":"A","en":"Meropenem plus ciprofloxacin plus linezolid","ar":"ميروبينيم مع سيبروفلوكساسين مع لينيزوليد"},{"letter":"B","en":"Mupirocin alone","ar":"ميوبيروسين وحده"},{"letter":"C","en":"Amoxicillin topical cream","ar":"كريم أموكسيسيلين موضعي"},{"letter":"D","en":"Azithromycin for five days only","ar":"أزيثروميسين خمسة أيام فقط"}],"correct":"A","explanation":{"en":"The example combines two bactericidal drugs with CNS penetration and a protein-synthesis inhibitor that reduces toxin production.","ar":"يجمع المثال بين دواءين قاتلين للبكتيريا ذوي نفاذ للجهاز العصبي ومثبط تصنيع بروتين يقلل إنتاج السموم."},"reasoning":{"en":"Focus on meningitis requires CNS-active combination therapy rather than monotherapy. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يتطلب التهاب السحايا علاجًا مركبًا فعالًا داخل الجهاز العصبي وليس علاجًا منفردًا. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q136","topic":"anthrax","topicEn":"Cutaneous Anthrax","topicAr":"الجمرة الخبيثة الجلدية","type":"MCQ","difficulty":"Hard","source":"PDF pp. 36, 38","question":{"en":"Why must anthrax antitoxin be combined with antibiotics?","ar":"لماذا يجب جمع مضاد سموم الجمرة الخبيثة مع المضادات الحيوية؟"},"options":[{"letter":"A","en":"Antitoxin neutralizes toxin but does not kill bacteria","ar":"مضاد السموم يعادل السم لكنه لا يقتل البكتيريا"},{"letter":"B","en":"Antibiotics neutralize toxin but never affect bacteria","ar":"المضادات تعادل السم ولا تؤثر في البكتيريا"},{"letter":"C","en":"Antitoxin works only as a topical moisturizer","ar":"مضاد السموم يعمل كمرطب موضعي فقط"},{"letter":"D","en":"The two drugs are identical","ar":"الدواءان متماثلان"}],"correct":"A","explanation":{"en":"Raxibacumab, obiltoxaximab, or anthrax immune globulin neutralizes toxin; antimicrobial therapy is still required to eradicate B. anthracis.","ar":"يعادل الراكسـيباكوماب أو الأوبيلتوكساكسيـماب أو الغلوبولين المناعي للجمرة السموم، لكن تبقى المضادات ضرورية للقضاء على البكتيريا."},"reasoning":{"en":"Focus on toxin control and bacterial killing are complementary therapeutic targets. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على السيطرة على السم وقتل البكتيريا هدفان علاجيان متكاملان. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q137","topic":"ssss","topicEn":"Staphylococcal Scalded Skin Syndrome","topicAr":"متلازمة الجلد المسموط العنقودية","type":"MCQ","difficulty":"Easy","source":"PDF p. 45","question":{"en":"What causes staphylococcal scalded skin syndrome?","ar":"ما سبب متلازمة الجلد المسموط العنقودية؟"},"options":[{"letter":"A","en":"Exfoliative toxins from toxigenic Staphylococcus aureus","ar":"سموم تقشرية من سلالات المكورات العنقودية الذهبية المنتجة للسموم"},{"letter":"B","en":"Direct invasion by Corynebacterium minutissimum","ar":"غزو مباشر بالوتدية الدقيقة"},{"letter":"C","en":"Bartonella invasion of lymph nodes","ar":"غزو بارتونيلا للعقد اللمفية"},{"letter":"D","en":"Bacillus anthracis spores in every case","ar":"أبواغ العصوية الجمرية في كل الحالات"}],"correct":"A","explanation":{"en":"SSSS is a toxin-mediated disorder caused by exfoliative toxin-producing S. aureus strains.","ar":"متلازمة الجلد المسموط اضطراب بوساطة السموم تسببه سلالات العنقوديات الذهبية المنتجة للسموم التقشرية."},"reasoning":{"en":"Focus on the skin findings are distant toxin effects rather than widespread bacterial invasion of each blister. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على النتائج الجلدية تأثيرات سمية بعيدة وليست غزوًا بكتيريًا لكل فقاعة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q138","topic":"ssss","topicEn":"Staphylococcal Scalded Skin Syndrome","topicAr":"متلازمة الجلد المسموط العنقودية","type":"MCQ","difficulty":"Hard","source":"PDF pp. 45-46","question":{"en":"Which adhesion protein is targeted by the exfoliative toxins in SSSS?","ar":"أي بروتين التصاق تستهدفه السموم التقشرية في متلازمة الجلد المسموط؟"},"options":[{"letter":"A","en":"Desmoglein-1","ar":"ديسموجلين-1"},{"letter":"B","en":"Collagen type IV","ar":"كولاجين النوع الرابع"},{"letter":"C","en":"Elastin only","ar":"الإيلاستين فقط"},{"letter":"D","en":"Keratin-18 exclusively","ar":"كيراتين-18 حصريًا"}],"correct":"A","explanation":{"en":"The toxins cleave desmoglein-1, causing superficial acantholysis in the stratum granulosum.","ar":"تشطر السموم ديسموجلين-1 مسببة فقد التماسك السطحي في الطبقة الحبيبية."},"reasoning":{"en":"Focus on the superficial cleavage level explains fragile bullae and mucosal sparing. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يفسر مستوى الانفصال السطحي الفقاعات الهشة وسلامة الأغشية المخاطية. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q139","topic":"ssss","topicEn":"Staphylococcal Scalded Skin Syndrome","topicAr":"متلازمة الجلد المسموط العنقودية","type":"MCQ","difficulty":"Medium","source":"PDF pp. 45-47","question":{"en":"Who is at greatest risk of SSSS?","ar":"من الأكثر عرضة لمتلازمة الجلد المسموط العنقودية؟"},"options":[{"letter":"A","en":"Infants, young children, and adults with renal failure or immunosuppression","ar":"الرضع والأطفال الصغار والبالغون المصابون بفشل كلوي أو تثبيط مناعة"},{"letter":"B","en":"Healthy adults only","ar":"البالغون الأصحاء فقط"},{"letter":"C","en":"Only adolescents with acne","ar":"المراهقون المصابون بحب الشباب فقط"},{"letter":"D","en":"Only patients with cat exposure","ar":"مرضى التعرض للقطط فقط"}],"correct":"A","explanation":{"en":"SSSS occurs mainly in infants and young children; adults are usually immunocompromised or have renal dysfunction that impairs toxin clearance.","ar":"تحدث المتلازمة أساسًا في الرضع والأطفال الصغار، ويكون البالغون غالبًا مثبطي المناعة أو لديهم خلل كلوي يضعف التخلص من السم."},"reasoning":{"en":"Focus on age and renal or immune status modify the ability to clear circulating toxin. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يؤثر العمر والحالة الكلوية أو المناعية في القدرة على التخلص من السم الدائر. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q140","topic":"ssss","topicEn":"Staphylococcal Scalded Skin Syndrome","topicAr":"متلازمة الجلد المسموط العنقودية","type":"Case","difficulty":"Medium","source":"PDF pp. 45-46","question":{"en":"An irritable febrile infant develops skin tenderness, diffuse erythema, fragile bullae, and superficial peeling. What is the most likely diagnosis?","ar":"رضيع متهيج ومحموم ظهرت لديه حساسية جلدية واحمرار منتشر وفقاعات هشة وتقشر سطحي. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Staphylococcal scalded skin syndrome","ar":"متلازمة الجلد المسموط العنقودية"},{"letter":"B","en":"Erythrasma","ar":"الإريثرازما"},{"letter":"C","en":"Furuncle","ar":"الدمل"},{"letter":"D","en":"Cat scratch disease","ar":"مرض خدش القطة"}],"correct":"A","explanation":{"en":"The acute sequence of fever, tenderness, diffuse erythema, fragile bullae, and desquamation is classic for SSSS.","ar":"التسلسل الحاد للحمى وألم الجلد والاحمرار المنتشر والفقاعات الهشة والتقشر كلاسيكي للمتلازمة."},"reasoning":{"en":"Focus on generalized superficial tenderness and peeling in an infant point to a toxin-mediated syndrome. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يشير الألم والتقشر السطحيان المعممان في رضيع إلى متلازمة بوساطة السموم. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q141","topic":"ssss","topicEn":"Staphylococcal Scalded Skin Syndrome","topicAr":"متلازمة الجلد المسموط العنقودية","type":"Case","difficulty":"Hard","source":"PDF pp. 45-46","question":{"en":"Which finding most strongly favors SSSS over toxic epidermal necrolysis?","ar":"أي علامة ترجح متلازمة الجلد المسموط على انحلال البشرة السمي؟"},"options":[{"letter":"A","en":"Absence of mucosal involvement","ar":"غياب إصابة الأغشية المخاطية"},{"letter":"B","en":"A positive Nikolsky sign alone","ar":"علامة نيكولسكي الإيجابية وحدها"},{"letter":"C","en":"Fever and skin pain","ar":"الحمى وألم الجلد"},{"letter":"D","en":"Widespread erythema","ar":"احمرار واسع"}],"correct":"A","explanation":{"en":"Mucosal surfaces are generally spared in SSSS because desmoglein-1 distribution differs, while TEN commonly involves mucosa.","ar":"تكون الأغشية المخاطية سليمة غالبًا في المتلازمة بسبب اختلاف توزيع ديسموجلين-1، بينما يصيبها انحلال البشرة السمي عادةً."},"reasoning":{"en":"Focus on Nikolsky positivity and fever may occur in both, so mucosal sparing is more discriminating. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على قد توجد علامة نيكولسكي والحمى في الحالتين، لذا سلامة المخاطية أكثر تمييزًا. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q142","topic":"ssss","topicEn":"Staphylococcal Scalded Skin Syndrome","topicAr":"متلازمة الجلد المسموط العنقودية","type":"Image","difficulty":"Medium","source":"PDF pp. 45-46","question":{"en":"The image shows widespread superficial peeling in a child with tender erythematous skin. Which diagnosis is most likely?","ar":"تُظهر الصورة تقشرًا سطحيًا واسعًا لدى طفل ذي جلد حمامي مؤلم. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Staphylococcal scalded skin syndrome","ar":"متلازمة الجلد المسموط العنقودية"},{"letter":"B","en":"Localized impetigo","ar":"قوباء موضعية"},{"letter":"C","en":"Erythrasma","ar":"إريثرازما"},{"letter":"D","en":"Ecthyma","ar":"إكثيما"}],"correct":"A","explanation":{"en":"Generalized superficial desquamation on tender erythematous skin in a child is characteristic of SSSS.","ar":"التقشر السطحي المعمم فوق جلد حمامي مؤلم لدى طفل مميز للمتلازمة."},"reasoning":{"en":"Focus on the generalized distribution separates it from localized bullous impetigo. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يفرق التوزع المعمم الحالة عن القوباء الفقاعية الموضعية. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":"data:image/webp;base64,"},{"id":"Q143","topic":"ssss","topicEn":"Staphylococcal Scalded Skin Syndrome","topicAr":"متلازمة الجلد المسموط العنقودية","type":"MCQ","difficulty":"Medium","source":"PDF p. 47","question":{"en":"What does a positive Nikolsky sign mean?","ar":"ماذا تعني علامة نيكولسكي الإيجابية؟"},"options":[{"letter":"A","en":"Gentle lateral pressure causes superficial skin separation","ar":"الضغط الجانبي الخفيف يسبب انفصال الجلد السطحي"},{"letter":"B","en":"The lesion fluoresces under Wood light","ar":"تتألق الآفة تحت مصباح وود"},{"letter":"C","en":"The lymph node is fluctuant","ar":"العقدة اللمفية متموجة"},{"letter":"D","en":"A black eschar is painless","ar":"القشرة السوداء غير مؤلمة"}],"correct":"A","explanation":{"en":"In a positive Nikolsky sign, gentle lateral pressure causes the superficial epidermis to peel or blister.","ar":"في علامة نيكولسكي الإيجابية يؤدي الضغط الجانبي الخفيف إلى تقشر أو تفقع البشرة السطحية."},"reasoning":{"en":"Focus on loss of superficial cell adhesion makes the epidermis shear easily. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يجعل فقد التصاق الخلايا السطحية البشرة تنفصل بسهولة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q144","topic":"ssss","topicEn":"Staphylococcal Scalded Skin Syndrome","topicAr":"متلازمة الجلد المسموط العنقودية","type":"Case","difficulty":"Hard","source":"PDF p. 47","question":{"en":"Where should cultures be taken in suspected SSSS?","ar":"من أين ينبغي أخذ المزارع عند الاشتباه في متلازمة الجلد المسموط؟"},"options":[{"letter":"A","en":"Nares, throat, conjunctiva, or a purulent primary focus rather than the sterile bullae","ar":"الأنف أو الحلق أو الملتحمة أو بؤرة قيحية أولية بدل الفقاعات العقيمة"},{"letter":"B","en":"Only from the clear bullous fluid","ar":"فقط من سائل الفقاعات الصافي"},{"letter":"C","en":"Only from normal intact skin","ar":"فقط من الجلد الطبيعي السليم"},{"letter":"D","en":"No culture site can ever be useful","ar":"لا يوجد موضع مفيد للمزرعة مطلقًا"}],"correct":"A","explanation":{"en":"Bullae are usually sterile because disease is toxin-mediated; the organism may be recovered from a primary colonization or infection site.","ar":"تكون الفقاعات عقيمة غالبًا لأن المرض بوساطة السموم، ويمكن عزل الميكروب من موضع استعمار أو عدوى أولية."},"reasoning":{"en":"Focus on sampling the toxin effect rather than the bacterial source gives low yield. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يكون مردود أخذ العينة من موضع تأثير السم بدل المصدر البكتيري منخفضًا. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q145","topic":"ssss","topicEn":"Staphylococcal Scalded Skin Syndrome","topicAr":"متلازمة الجلد المسموط العنقودية","type":"Case","difficulty":"Hard","source":"PDF pp. 47-48","question":{"en":"What is the appropriate disposition for a patient with SSSS?","ar":"ما المكان المناسب لعلاج مريض متلازمة الجلد المسموط؟"},"options":[{"letter":"A","en":"Hospital admission, with burn-unit or ICU care if severe or adult","ar":"دخول المستشفى مع وحدة حروق أو عناية مركزة إذا كانت الحالة شديدة أو في بالغ"},{"letter":"B","en":"Routine outpatient moisturizer only","ar":"مرطب روتيني بالعيادة فقط"},{"letter":"C","en":"Discharge without analgesia","ar":"خروج دون مسكنات"},{"letter":"D","en":"Elective review after six months","ar":"مراجعة اختيارية بعد ستة أشهر"}],"correct":"A","explanation":{"en":"SSSS requires hospitalization for IV antibiotics, fluid management, pain control, and careful wound care.","ar":"تحتاج المتلازمة دخول المستشفى للمضادات الوريدية وإدارة السوائل والألم والعناية الدقيقة بالجروح."},"reasoning":{"en":"Focus on large-area barrier loss creates dehydration, pain, and infection risks similar to a superficial burn. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يخلق فقد الحاجز واسع المساحة مخاطر الجفاف والألم والعدوى المشابهة للحروق السطحية. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q146","topic":"ssss","topicEn":"Staphylococcal Scalded Skin Syndrome","topicAr":"متلازمة الجلد المسموط العنقودية","type":"Treatment","difficulty":"Medium","source":"PDF p. 47","question":{"en":"Which IV antibiotics are first-line for MSSA-associated SSSS?","ar":"ما المضادات الوريدية خط الأول للمتلازمة المرتبطة بـMSSA؟"},"options":[{"letter":"A","en":"Oxacillin or nafcillin","ar":"أوكساسيلين أو نافسيلين"},{"letter":"B","en":"Azithromycin only","ar":"أزيثروميسين فقط"},{"letter":"C","en":"Ciprofloxacin topical drops","ar":"قطرات سيبروفلوكساسين موضعية"},{"letter":"D","en":"Rifampin monotherapy","ar":"ريفامبين وحده"}],"correct":"A","explanation":{"en":"An antistaphylococcal penicillin such as oxacillin or nafcillin is first-line; cefazolin is an alternative when appropriate.","ar":"يُعد البنسلين المضاد للعنقوديات مثل الأوكساسيلين أو النافسيلين خطًا أول، والسيفازولين بديلًا مناسبًا."},"reasoning":{"en":"Focus on treatment targets the toxin-producing S. aureus source. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يستهدف العلاج مصدر العنقوديات المنتجة للسم. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q147","topic":"ssss","topicEn":"Staphylococcal Scalded Skin Syndrome","topicAr":"متلازمة الجلد المسموط العنقودية","type":"Treatment","difficulty":"Medium","source":"PDF pp. 45, 47","question":{"en":"What should be used when MRSA is suspected in SSSS?","ar":"ما العلاج المستخدم عند الاشتباه في MRSA في متلازمة الجلد المسموط؟"},"options":[{"letter":"A","en":"Vancomycin","ar":"فانكوميسين"},{"letter":"B","en":"Penicillin V alone","ar":"بنسلين V وحده"},{"letter":"C","en":"Topical fusidic acid alone","ar":"حمض الفيوسيديك موضعي وحده"},{"letter":"D","en":"No antibiotic therapy","ar":"عدم استخدام مضاد"}],"correct":"A","explanation":{"en":"Vancomycin is appropriate when MRSA is suspected or local resistance makes standard MSSA therapy unreliable.","ar":"يُعد الفانكوميسين مناسبًا عند الاشتباه في MRSA أو عندما تجعل المقاومة المحلية علاج MSSA المعتاد غير موثوق."},"reasoning":{"en":"Focus on resistance risk changes the definitive antistaphylococcal agent. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يغير خطر المقاومة الدواء النهائي المضاد للعنقوديات. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q148","topic":"ssss","topicEn":"Staphylococcal Scalded Skin Syndrome","topicAr":"متلازمة الجلد المسموط العنقودية","type":"Treatment","difficulty":"Hard","source":"PDF p. 47","question":{"en":"What is the correct role of clindamycin in SSSS?","ar":"ما الدور الصحيح للكليندامايسين في متلازمة الجلد المسموط؟"},"options":[{"letter":"A","en":"Adjunct to reduce toxin production, not reliable monotherapy","ar":"علاج مساعد لتقليل إنتاج السم وليس علاجًا منفردًا موثوقًا"},{"letter":"B","en":"Preferred monotherapy in every case","ar":"العلاج المنفرد المفضل في كل الحالات"},{"letter":"C","en":"Only a topical moisturizer","ar":"مرطب موضعي فقط"},{"letter":"D","en":"Contraindicated even as adjunct","ar":"ممنوع حتى كعلاج مساعد"}],"correct":"A","explanation":{"en":"Clindamycin may suppress toxin production, but resistance is substantial, so it should not be used alone.","ar":"قد يقلل الكليندامايسين إنتاج السم، لكن المقاومة مرتفعة ولذلك لا ينبغي استخدامه وحده."},"reasoning":{"en":"Focus on toxin suppression complements, but cannot replace, reliable bactericidal coverage. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يكمل تثبيط السم التغطية الموثوقة القاتلة للبكتيريا ولا يستبدلها. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q149","topic":"ssss","topicEn":"Staphylococcal Scalded Skin Syndrome","topicAr":"متلازمة الجلد المسموط العنقودية","type":"Treatment","difficulty":"Medium","source":"PDF pp. 47-48","question":{"en":"Which supportive-care plan is most appropriate in SSSS?","ar":"أي خطة رعاية داعمة هي الأنسب في متلازمة الجلد المسموط؟"},"options":[{"letter":"A","en":"IV fluids as needed, analgesia, gentle non-adherent petrolatum dressings, and minimal friction","ar":"سوائل وريدية حسب الحاجة ومسكنات وضمادات فازلين لطيفة غير لاصقة وتقليل الاحتكاك"},{"letter":"B","en":"Aggressive scrubbing and adhesive dressings","ar":"فرك قوي وضمادات لاصقة"},{"letter":"C","en":"Routine debridement of all peeling skin","ar":"تنضير روتيني لكل الجلد المتقشر"},{"letter":"D","en":"Withhold pain control during dressing changes","ar":"منع المسكنات أثناء تغيير الضماد"}],"correct":"A","explanation":{"en":"Care should protect the fragile barrier, replace fluid losses, control pain, and use gentle non-adherent dressings.","ar":"ينبغي أن تحمي الرعاية الحاجز الهش وتعوض السوائل وتسيطر على الألم وتستخدم ضمادات لطيفة غير لاصقة."},"reasoning":{"en":"Focus on supportive management prevents secondary injury while the epidermis regenerates. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تمنع الرعاية الداعمة الإصابة الثانوية أثناء تجدد البشرة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q150","topic":"ssss","topicEn":"Staphylococcal Scalded Skin Syndrome","topicAr":"متلازمة الجلد المسموط العنقودية","type":"Case","difficulty":"Hard","source":"PDF p. 48","question":{"en":"A team proposes surgical debridement of widespread peeling skin in SSSS. What is the best response?","ar":"اقترح فريق تنضير الجلد المتقشر على نطاق واسع في متلازمة الجلد المسموط. ما الرد الأفضل؟"},"options":[{"letter":"A","en":"Avoid debridement because it adds trauma and does not improve recovery","ar":"تجنب التنضير لأنه يزيد الرض ولا يحسن التعافي"},{"letter":"B","en":"Proceed routinely because all peeling skin is necrotic fascia","ar":"إجراؤه روتينيًا لأن كل الجلد المتقشر لفافة نخرية"},{"letter":"C","en":"Debride before starting antibiotics","ar":"التنضير قبل بدء المضادات"},{"letter":"D","en":"Use only sharp curettage at home","ar":"استخدام الكحت الحاد في المنزل فقط"}],"correct":"A","explanation":{"en":"Debridement is not helpful in SSSS and can prolong discomfort and hospitalization; gentle wound care is preferred.","ar":"لا يفيد التنضير في المتلازمة وقد يطيل الألم والإقامة، وتُفضل العناية اللطيفة بالجروح."},"reasoning":{"en":"Focus on superficial toxin-mediated separation is not the same as surgically removable necrotizing infection. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على الانفصال السطحي بوساطة السموم ليس عدوى نخرية قابلة للإزالة جراحيًا. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null}]);
